// Parse Discord slash command payload
const body = $input.first().json.body;
let sources = [];

// Extract source from command text: /crawl facebook, /crawl linkedin, or /crawl (both)
const content = (body.content || body.data?.options?.[0]?.value || '').trim().toLowerCase();
if (content === 'facebook' || content === 'linkedin') {
  sources = [content];
}
// empty sources = crawl all enabled

return [{ json: { sources } }];

// Dedup: filter out jobs already in Data Tables
const crawlResult = $('Call Crawler API').first().json;
const existingJobs = $('Get Existing Jobs').all().map(item => item.json.job_id);
const existingSet = new Set(existingJobs);

const newJobs = crawlResult.jobs.filter(j => !existingSet.has(j.job_id));

return [{ json: { newJobs, totalCrawled: crawlResult.total_jobs, totalNew: newJobs.length } }];

// Split new jobs into individual items for insert + Discord
const { newJobs } = $input.first().json;
return newJobs.map(j => ({ json: j }));
